SELECT ,
       e.emp_name, e.emp_no, d.dept_name,
       a.emp_name as approver_name
FROM sys_overtime o
LEFT JOIN sys_emp e ON o.emp_id = e.id
LEFT JOIN sys_dept d ON e.dept_id = d.id
LEFT JOIN sys_emp a ON o.approver_id = a.id


        AND o.emp_id = #{empId}


        AND e.emp_name LIKE CONCAT('%', #{empName}, '%')


        AND o.overtime_type = #{overtimeType}


        AND o.status = #{status}


         AND o.overtime_date >= #{startDate} 


         AND o.overtime_date <= #{endDate} 


ORDER BY o.overtime_date DESC, o.create_time DESC

mapper.update:
UPDATE sys_overtime
overtime_date = #{overtimeDate}, start_time = #{startTime}, end_time = #{endTime}, overtime_hours = #{overtimeHours}, overtime_type = #{overtimeType}, reason = #{reason}, status = #{status},
WHERE id = #{id}

UPDATE sys_overtime
SET status = #{status},
    approver_id = #{approverId},
    approve_time = #{approveTime}
WHERE id = #{id}
